class Solution:
    def minimumSize(self, nums, maxOperations):
        def ops_needed(m):
            return sum((v - 1) // m for v in nums)
        lo, hi = 1, max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if ops_needed(mid) <= maxOperations:
                hi = mid
            else:
                lo = mid + 1
        return lo

