var minimumSize = function(nums, maxOperations) {
    let lo = 1, hi = Math.max(...nums);
    while (lo < hi) {
        const m = Math.floor((lo + hi) / 2);
        let cost = 0;
        for (const v of nums) cost += Math.floor((v - 1) / m);
        if (cost <= maxOperations) hi = m; else lo = m + 1;
    }
    return lo;
};
